kubectl -n mongodb exec mongodb-replica-0 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
// 1. Create reportingRole in appdb with aggregate privilege on appdb.reports
db.getSiblingDB("appdb").createRole({
  role: "reportingRole",
  privileges: [{
    resource: { db: "appdb", collection: "reports" },
    actions: ["find", "aggregate"]
  }],
  roles: []
});
print("reportingRole created");
' 2>&1 | grep -v "^Current\|^Connecting\|^MongoSh\|^Using\|^For mongosh\|anonymous"
